import React, { useState } from 'react';

function GameList({ games, onDelete, onEdit }) {
  const [editingId, setEditingId] = useState(null);
  const [editData, setEditData] = useState({ title: '', status: 'planned', rating: 0 });

  const startEdit = (game) => {
    setEditingId(game._id);
    setEditData({ title: game.title, status: game.status, rating: game.rating });
  };

  const submitEdit = (e) => {
    e.preventDefault();
    onEdit(editingId, editData);
    setEditingId(null);
  };

  return (
    <div>
      <h3>Игры</h3>
      {games.map((game) => (
        <div key={game._id} style={{ border: '1px solid #ccc', padding: '8px', margin: '4px' }}>
          {editingId === game._id ? (
            <form onSubmit={submitEdit}>
              <input
                value={editData.title}
                onChange={(e) => setEditData({ ...editData, title: e.target.value })}
              />
              <select
                value={editData.status}
                onChange={(e) => setEditData({ ...editData, status: e.target.value })}
              >
                <option value="playing">Играю</option>
                <option value="completed">Завершена</option>
                <option value="planned">Запланирована</option>
              </select>
              <input
                type="number"
                value={editData.rating}
                onChange={(e) => setEditData({ ...editData, rating: e.target.value })}
                min="0"
                max="10"
              />
              <button type="submit">Сохранить</button>
              <button type="button" onClick={() => setEditingId(null)}>
                Отмена
              </button>
            </form>
          ) : (
            <>
              <p>Название: {game.title}</p>
              <p>Статус: {game.status}</p>
              <p>Рейтинг: {game.rating}</p>
              <button onClick={() => startEdit(game)}>Редактировать</button>
              <button onClick={() => onDelete(game._id)}>Удалить</button>
            </>
          )}
        </div>
      ))}
    </div>
  );
}

export default GameList;
